// --- BOOKING CONFIRMATION ---
function setCxlPolicy(type){
  document.getElementById('cf-cxl').value=type==='refundable'
    ?'Your reservation is cancellable up to X days prior to arrival'
    :'Your reservation is non refundable';
  document.getElementById('cxl-tog-ref').classList.toggle('active',type==='refundable');
  document.getElementById('cxl-tog-non').classList.toggle('active',type==='nonrefundable');
}
let cals2={cfi:{y:2026,m:3},cfo:{y:2026,m:3}};
let picked2={cfi:null,cfo:null};
let inp2={cfi:'cf-in',cfo:'cf-out'};
let photoDataUrl=null;

function toggleTimePick(selId,cb){
  document.getElementById(selId).style.display=cb.checked?'block':'none';
}

function tc2(id){
  const pop=document.getElementById(id);
  const was=pop.classList.contains('open');
  document.querySelectorAll('.cal-pop').forEach(p=>p.classList.remove('open'));
  if(!was){rc2(id);pop.classList.add('open');}
}
function rc2(id){
  const{y,m}=cals2[id];
  const first=new Date(y,m,1).getDay();
  const dim=new Date(y,m+1,0).getDate();
  const td=new Date();
  const s=picked2[id];
  let h=`<div class="cal-nav"><button onclick="cn2(event,'${id}',-1)">‹</button><span>${MONTHS[m]} ${y}</span><button onclick="cn2(event,'${id}',1)">›</button></div><div class="cal-grid">`;
  DNAMES.forEach(d=>h+=`<div class="cdn">${d}</div>`);
  for(let i=0;i<first;i++)h+=`<div class="cd em"></div>`;
  for(let d=1;d<=dim;d++){
    const it=d===td.getDate()&&m===td.getMonth()&&y===td.getFullYear();
    const is=s&&s.d===d&&s.m===m&&s.y===y;
    h+=`<div class="cd${it?' td':''}${is?' sel':''}" onclick="pd2('${id}',${y},${m},${d})">${d}</div>`;
  }
  h+=`</div>`;
  document.getElementById(id).innerHTML=h;
}
function cn2(e,id,dir){
  e.stopPropagation();
  let{y,m}=cals2[id];m+=dir;
  if(m<0){m=11;y--;}if(m>11){m=0;y++;}
  cals2[id]={y,m};rc2(id);
}
function pd2(id,y,m,d){
  picked2[id]={y,m,d};
  const months=['January','February','March','April','May','June','July','August','September','October','November','December'];
  const days=['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'];
  const sfx=d%10===1&&d!==11?'st':d%10===2&&d!==12?'nd':d%10===3&&d!==13?'rd':'th';
  document.getElementById(inp2[id]).value=`${days[new Date(y,m,d).getDay()]}, ${d}${sfx} of ${months[m]} ${y}`;
  document.getElementById(id).classList.remove('open');
}

function previewPhoto(input){
  const file=input.files[0];
  if(!file)return;
  const reader=new FileReader();
  reader.onload=e=>{
    photoDataUrl=e.target.result;
    document.getElementById('cf-photo-img').src=photoDataUrl;
    document.getElementById('cf-photo-preview').style.display='block';
  };
  reader.readAsDataURL(file);
}

let cfCropper=null;
function startCrop(){
  if(cfCropper){cfCropper.destroy();cfCropper=null;}
  document.getElementById('cf-photo-preview').style.display='none';
  document.getElementById('cf-crop-area').style.display='block';
  const img=document.getElementById('cf-crop-img');
  img.src=photoDataUrl;
  const doInit=()=>{
    if(cfCropper)return;
    cfCropper=new Cropper(img,{aspectRatio:435/260,viewMode:1,autoCropArea:1});
  };
  // img.decode() resolves once the image is fully decoded — more reliable than onload with data URLs
  if(typeof img.decode==='function'){
    img.decode().then(()=>requestAnimationFrame(doInit)).catch(doInit);
  } else {
    img.onload=doInit;
    if(img.complete && img.naturalWidth>0) doInit();
  }
}
function applyCrop(){
  if(!cfCropper)return;
  const canvas=cfCropper.getCroppedCanvas({width:870,height:520});
  if(!canvas)return;
  photoDataUrl=canvas.toDataURL('image/jpeg',0.95);
  document.getElementById('cf-photo-img').src=photoDataUrl;
  cfCropper.destroy();cfCropper=null;
  document.getElementById('cf-crop-area').style.display='none';
  document.getElementById('cf-photo-preview').style.display='block';
}
function cancelCrop(){
  if(cfCropper){cfCropper.destroy();cfCropper=null;}
  document.getElementById('cf-crop-area').style.display='none';
  document.getElementById('cf-photo-preview').style.display='block';
}

